queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?image_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasImages ?child ; p:hasPhotojournalism_Pieces ?parent . } GROUP BY ?child }
  ?child p:image_name ?image_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photojournalism_Pieces } }
  FILTER(?nf = ?total)
}

