PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?image_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasImages ?child ; p:hasPhotojournalism_Pieces ?parent . } GROUP BY ?child }
  ?child p:image_name ?image_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photojournalism_Pieces } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?title ?image_name WHERE {
  ?photojournalism_pieces_images a :Photojournalism_Pieces_Images .
  ?images a :Images .
  ?photojournalism_pieces_images p:hasImages ?images .
  ?photojournalism_pieces a :Photojournalism_Pieces .
  ?photojournalism_pieces_images p:hasPhotojournalism_Pieces ?photojournalism_pieces .
  ?photojournalism_pieces p:title ?title .
  ?images p:image_name ?image_name .
} }
}

